import { Platform } from 'react-native';

const BASE_API_URL = 'https://api.example.com';
const LOCAL_IOT_DEVICE_URL = 'http://192.168.x.x';

const API_HEADERS = {
  Accept: 'application/json',
  'Content-Type': 'application/json',
};

async function fetchData(url, method = 'GET', body = null) {
  const isApiRequest = url.startsWith(BASE_API_URL);
  const headers = { ...API_HEADERS };

  if (!isApiRequest) {
    headers['Connection'] = 'keep-alive';
  }

  let options = {
    method,
    headers,
  };

  if (body) {
    options.body = JSON.stringify(body);
  }

  try {
    const response = await fetch(url, options);

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    return await response.json();
  } catch (error) {
    console.error('Fetch error:', error);
    throw error;
  }
}

// Example usage for API request
fetchData(`${BASE_API_URL}/data`, 'GET')
  .then(data => console.log(data))
  .catch(error => console.error(error));

// Example usage for local IoT device request
fetchData(LOCAL_IOT_DEVICE_URL, 'POST', { action: 'toggle' })
  .then(response => console.log('Device response:', response))
  .catch(error => console.error(error));